def validate_email_field(raw: Any, errors: list[ValidationErrorItem]) -> EmailValue | None:
    if not isinstance(raw, str):
        add_error(errors, "email", "invalid_type", "Email must be a string.")
        return None

    normalized_input = unicodedata.normalize("NFKC", raw)
    stripped = normalized_input.strip()

    if stripped != normalized_input:
        add_error(errors, "email", "surrounding_whitespace", "Email must not have leading or trailing whitespace.")

    if len(stripped) > 254:
        add_error(errors, "email", "too_long", "Email must be at most 254 characters.")

    if any(ch.isspace() for ch in stripped):
        add_error(errors, "email", "whitespace", "Email must not contain whitespace.")

    if "\r" in stripped or "\n" in stripped:
        add_error(errors, "email", "header_injection", "Email must not contain line breaks.")

    if has_disallowed_codepoint(stripped):
        add_error(errors, "email", "unsafe_unicode", "Email contains unsafe Unicode control or direction characters.")

    if stripped.count("@") != 1:
        add_error(errors, "email", "invalid_format", "Enter a valid email address.")
        return None

    try:
        validated = validate_email(
            stripped,
            check_deliverability=False,
            allow_smtputf8=False,
            allow_quoted_local=False,
            allow_domain_literal=False,
        )
    except EmailNotValidError:
        add_error(errors, "email", "invalid_format", "Enter a valid email address.")
        return None

    local = validated.local_part
    domain_unicode = validated.domain

    if len(local.encode("utf-8")) > 64:
        add_error(errors, "email", "local_part_too_long", "Email local part is too long.")

    if any(ord(ch) > 127 for ch in local):
        add_error(errors, "email", "unicode_local_part", "Unicode email local parts are not accepted.")

    try:
        domain_ascii = idna.encode(domain_unicode, uts46=True, std3_rules=True).decode("ascii").lower()
    except idna.IDNAError:
        add_error(errors, "email", "bad_domain", "Email domain is invalid.")
        return None

    labels = domain_ascii.split(".")
    tld = labels[-1]

    if "." not in domain_ascii:
        add_error(errors, "email", "domain_requires_tld", "Email domain must have a valid public suffix.")

    if domain_ascii in RESERVED_EMAIL_DOMAINS or tld in RESERVED_TLDS:
        add_error(errors, "email", "reserved_domain", "Email domain is not allowed.")

    if domain_ascii in DISPOSABLE_EMAIL_DOMAINS or any(domain_ascii.endswith("." + d) for d in DISPOSABLE_EMAIL_DOMAINS):
        add_error(errors, "email", "disposable_domain", "Disposable email domains are not allowed.")

    if any(not label or len(label) > 63 or label.startswith("-") or label.endswith("-") for label in labels):
        add_error(errors, "email", "bad_domain_label", "Email domain contains an invalid label.")

    if tld.isdigit():
        add_error(errors, "email", "numeric_tld", "Email top-level domain is invalid.")

    if EMAIL_DNS_CHECK and dns is not None and not email_domain_accepts_mail(domain_ascii):
        add_error(errors, "email", "undeliverable_domain", "Email domain does not appear to accept mail.")

    email_normalized = f"{local.casefold()}@{domain_ascii}"
    return EmailValue(normalized=email_normalized, domain_ascii=domain_ascii, local_part=local.casefold())


def email_domain_accepts_mail(domain_ascii: str) -> bool:
    resolver = dns.resolver.Resolver()
    resolver.lifetime = 2.0
    resolver.timeout = 2.0

    try:
        mx_records = resolver.resolve(domain_ascii, "MX")
        for record in mx_records:
            if str(record.exchange).strip(".") == "":
                return False
        return True
    except Exception:
        pass

    for record_type in ("A", "AAAA"):
        try:
            if list(resolver.resolve(domain_ascii, record_type)):
                return True
        except Exception:
            continue

    return False


def validate_username_field(raw: Any, errors: list[ValidationErrorItem]) -> UsernameValue | None:
    if not isinstance(raw, str):
        add_error(errors, "username", "invalid_type", "Username must be a string.")
        return None

    normalized = unicodedata.normalize("NFKC", raw).strip()

    if normalized != raw:
        add_error(errors, "username", "normalized", "Username must not need trimming or Unicode normalization.")

    if has_disallowed_codepoint(normalized):
        add_error(errors, "username", "unsafe_unicode", "Username contains unsafe Unicode characters.")

    if any(ord(ch) > 127 for ch in normalized):
        add_error(errors, "username", "ascii_only", "Username may only contain ASCII letters, numbers, dots, dashes, and underscores.")

    if len(normalized) < 3:
        add_error(errors, "username", "too_short", "Username must be at least 3 characters.")

    if len(normalized) > 32:
        add_error(errors, "username", "too_long", "Username must be at most 32 characters.")

    if len(normalized.encode("utf-8")) > 64:
        add_error(errors, "username", "too_many_bytes", "Username is too large.")

    if not USERNAME_RE.fullmatch(normalized):
        add_error(errors, "username", "invalid_characters", "Username contains invalid characters.")

    if normalized.endswith((".", "-", "_")):
        add_error(errors, "username", "bad_edge_character", "Username must not end with punctuation.")

    if any(seq in normalized for seq in ("..", "__", "--", ".-", "-.", "._", "_.")):
        add_error(errors, "username", "repeated_punctuation", "Username must not contain repeated or adjacent punctuation.")

    if normalized.isdigit():
        add_error(errors, "username", "all_digits", "Username must not be only numbers.")

    compact = compact_identifier(normalized)

    if compact in RESERVED_USERNAMES or compact.rstrip("0123456789") in RESERVED_USERNAMES:
        add_error(errors, "username", "reserved", "Username is not available.")

    if any(term in compact for term in BANNED_USERNAME_TERMS):
        add_error(errors, "username", "blocked_content", "Username is not allowed.")

    return UsernameValue(display=normalized, key=normalized.casefold())


def sanitize_display_name(raw: Any, errors: list[ValidationErrorItem]) -> str | None:
