    if "<" in raw or ">" in raw or cleaned != collapsed:
        add_error(errors, "display_name", "markup_not_allowed", "Display name must not contain HTML or markup.")

    if URL_RE.search(collapsed):
        add_error(errors, "display_name", "url_not_allowed", "Display name must not contain URLs.")

    if len(cleaned) < 1:
        add_error(errors, "display_name", "required", "Display name is required.")

    if len(cleaned) > 80:
        add_error(errors, "display_name", "too_long", "Display name must be at most 80 characters.")

    if len(cleaned.encode("utf-8")) > 160:
