def validate_password_field(
    raw: Any,
    username: UsernameValue | None,
    email: EmailValue | None,
    display_name: str | None,
    errors: list[ValidationErrorItem],
) -> str | None:
    if not isinstance(raw, str):
        add_error(errors, "password", "invalid_type", "Password must be a string.")
        return None

    password = raw
    analyzed = unicodedata.normalize("NFKC", password)

    if len(password) < MIN_PASSWORD_CHARS:
        add_error(errors, "password", "too_short", f"Password must be at least {MIN_PASSWORD_CHARS} characters.")

    if len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        add_error(errors, "password", "too_long", "Password is too long.")

    if password != password.strip():
        add_error(errors, "password", "surrounding_whitespace", "Password must not start or end with whitespace.")

    if has_disallowed_codepoint(password):
        add_error(errors, "password", "unsafe_characters", "Password contains unsafe control or direction characters.")

    categories = {
        "lower": any(ch.islower() for ch in password),
        "upper": any(ch.isupper() for ch in password),
        "digit": any(ch.isdigit() for ch in password),
        "symbol": any(not ch.isalnum() and not ch.isspace() for ch in password),
    }

    if sum(categories.values()) < 3:
        add_error(errors, "password", "complexity", "Password must include at least three of: lowercase, uppercase, number, symbol.")

    compact_password = compact_identifier(analyzed)

    if compact_password in COMMON_PASSWORDS:
        add_error(errors, "password", "common_password", "Password is too common.")

    if re.search(r"(.)\1{3,}", analyzed):
        add_error(errors, "password", "repeated_characters", "Password has too many repeated characters.")

    lowered = analyzed.casefold()
    for seq in SEQUENCES:
        for i in range(0, len(seq) - 4):
            piece = seq[i : i + 5]
            if piece in lowered or piece[::-1] in lowered:
                add_error(errors, "password", "sequential_characters", "Password contains an obvious sequence.")
                break

    if re.search(r"(19[5-9]\d|20[0-3]\d)", lowered):
        add_error(errors, "password", "predictable_year", "Password must not contain an obvious year.")

    similarity_tokens = []
    if username:
        similarity_tokens.append(username.key)
    if email:
        similarity_tokens.extend([email.local_part, email.domain_ascii.split(".")[0]])
    if display_name:
        similarity_tokens.append(display_name)

    for token in similarity_tokens:
        if is_too_similar(compact_password, compact_identifier(token)):
            add_error(errors, "password", "too_similar", "Password must not be similar to your email, username, or display name.")
            break

    return password


def is_too_similar(password_compact: str, token_compact: str) -> bool:
    if len(token_compact) < 4:
        return False
    if token_compact in password_compact:
        return True
    return SequenceMatcher(None, password_compact, token_compact).ratio() >= 0.72


async def password_seen_in_breach(password: str) -> bool | None:
    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]

    try:
        async with httpx.AsyncClient(timeout=2.5) as client:
            response = await client.get(
                f"https://api.pwnedpasswords.com/range/{prefix}",
                headers={"Add-Padding": "true", "User-Agent": "registration-security-check"},
            )
        if response.status_code != 200:
            return None

        for line in response.text.splitlines():
            candidate, _, _count = line.partition(":")
            if hmac.compare_digest(candidate.strip().upper(), suffix):
                return True
        return False
    except httpx.HTTPError:
        return None


async def validate_registration_payload(data: Any) -> tuple[list[ValidationErrorItem], CleanRegistration | None]:
    errors: list[ValidationErrorItem] = []

    if not isinstance(data, dict):
        add_error(errors, "_request", "invalid_json_object", "JSON body must be an object.")
        return errors, None

    allowed = {"email", "username", "password", "display_name"}
    required = {"email", "username", "password", "display_name"}

    for field in sorted(required - data.keys()):
        add_error(errors, field, "required", f"{field} is required.")

    for field in sorted(data.keys() - allowed):
        add_error(errors, field, "unknown_field", "Unknown field is not allowed.")

    email = validate_email_field(data.get("email"), errors) if "email" in data else None
    username = validate_username_field(data.get("username"), errors) if "username" in data else None
    display_name = sanitize_display_name(data.get("display_name"), errors) if "display_name" in data else None
    password = validate_password_field(data.get("password"), username, email, display_name, errors) if "password" in data else None

    if password and len(password) <= MAX_PASSWORD_CHARS and HIBP_ENABLED:
        breached = await password_seen_in_breach(password)
        if breached is True:
            add_error(errors, "password", "breached_password", "Password has appeared in a known data breach.")
        elif breached is None and HIBP_FAIL_CLOSED:
            add_error(errors, "password", "breach_check_unavailable", "Password breach check is temporarily unavailable.")

    if errors or not email or not username or display_name is None or password is None:
        return errors, None

    return errors, CleanRegistration(email=email, username=username, display_name=display_name, password=password)


async def equalize_valid_response_time(started: float) -> None:
