    if errors:
        return structured_error(status.HTTP_422_UNPROCESSABLE_ENTITY, errors)

    retry_after = email_register_limiter.hit(secret_hmac(f"register:email:{clean.email.normalized}"))
    if retry_after is not None:
        return JSONResponse(
            status_code=status.HTTP_429_TOO_MANY_REQUESTS,
            headers={"Retry-After": str(retry_after)},
            content={
                "ok": False,
                "errors": [
                    {
                        "field": "_request",
                        "code": "rate_limited",
                        "message": "Too many registration attempts. Try again later.",
                    }
                ],
            },
        )

    # Hash before duplicate checks so duplicate and non-duplicate submissions have closer timing.
    password_hash = password_hasher.hash(clean.password)

    db = SessionLocal()
    try:
        existing = db.scalar(
            select(User.id)
            .where(
                or_(
                    User.email_normalized == clean.email.normalized,
                    User.username_key == clean.username.key,
                )
            )
            .limit(1)
        )

        if existing is None:
            db.add(
                User(
                    email_normalized=clean.email.normalized,
                    email_domain=clean.email.domain_ascii,
                    username=clean.username.display,
                    username_key=clean.username.key,
                    display_name=clean.display_name,
                    password_hash=password_hash,
                    is_email_verified=False,
                )
            )
            db.commit()

    except IntegrityError:
        # Handles concurrent duplicate registrations without leaking which field collided.
        db.rollback()
    finally:
        db.close()

    await equalize_valid_response_time(started)
    return generic_register_response()
```

Run:

```bash
uvicorn main:app --reload
```

The endpoint returns `422` with all validation failures for bad input, `429` for rate limits, `400/413/415` for bad requests, and a generic `202` for valid registration attempts so duplicate emails are not exposed.
